// Anmeldedaten normalisieren + validieren
const body = $input.first().json.body || $input.first().json;

let name = body.name || body.Name || body.schuelerName || '';
const vorname = body.vorname || body.Vorname || '';
const nachname = body.nachname || body.Nachname || '';
if (!name && vorname && nachname) name = `${vorname} ${nachname}`;

let telefon = (body.telefon || body.phone || body.Telefon || body.Handy || '').toString();
const email = (body.email || body.Email || '').trim();
const klasse = body.klasse || body.Klasse || body.fuehrerscheinKlasse || 'B';
const geburtsdatum = body.geburtsdatum || body.Geburtsdatum || '';
const adresse = body.adresse || body.Adresse || '';
const anmerkungen = body.anmerkungen || body.Anmerkungen || body.nachricht || '';
const wunschTermin = body.wunschTermin || body.wunsch_termin || '';

// Telefonnummer bereinigen
telefon = telefon.replace(/[\s\-\/\(\)]/g, '');
if (telefon && !telefon.startsWith('+')) {
  telefon = '+49' + telefon.replace(/^0/, '');
}

// Schueler-ID generieren (URL-safe, kollisionsarm)
const schuelerId = 'SCH-' + Date.now().toString(36).toUpperCase() + Math.random().toString(36).slice(2,5).toUpperCase();

return [{
  json: {
    schuelerId,
    schuelerName: name,
    vorname,
    nachname,
    telefon,
    email,
    klasse,
    geburtsdatum,
    adresse,
    anmerkungen,
    wunschTermin,
    anmeldeDatum: new Date().toISOString(),
    hatEmail: email.length > 0 && email.includes('@'),
    hatTelefon: telefon.length > 5,
    status: 'angemeldet'
  }
}];

