// ============================================================
// ONBOARDING FOLLOW-UP LOGIC
// Tag 3: Dokumente-Erinnerung
// Tag 7: Dokumente-Erinnerung (dringender) + Theorie-Termin
// Tag 14: Letzte Warnung Dokumente
// Tag 7 (mit Fahrlehrer): Theorie-Termin vorschlagen
// ============================================================
const schueler = $('Alle Schueler laden').all();
const logItems = $('Onboarding-Log laden').all();

// Cooldown-Map: telefon_schritt -> letztes Sendedatum
const gesendet = new Set();
for (const item of logItems) {
  const key = `${item.json.Telefon}_${item.json.Schritt}`;
  gesendet.add(key);
}

const now = new Date();
const results = [];

for (const item of schueler) {
  const data = item.json;

  const status = (data.Status || '').toLowerCase();
  if (status === 'abgemeldet' || status === 'storniert' || status === 'bestanden') continue;

  const name = data.Name || data.Schueler || '';
  let telefon = (data.Telefon || '').toString().replace(/[\s\-\/\(\)]/g, '');
  if (!telefon.startsWith('+')) telefon = '+49' + telefon.replace(/^0/, '');

  const anmeldeDatum = data.Anmelde_Datum || '';
  const dokuStatus = (data.Dokumente_Status || '').toLowerCase();
  const fahrlehrer = data.Fahrlehrer || '';
  const theorieStatus = (data.Theorie_Status || '').toLowerCase();
  const klasse = data.Klasse || 'B';

  if (!telefon || !name || !anmeldeDatum) continue;

  let anmeldung;
  try { anmeldung = new Date(anmeldeDatum); } catch(e) { continue; }
  if (isNaN(anmeldung.getTime())) continue;

  const tageSeit = Math.floor((now.getTime() - anmeldung.getTime()) / (1000 * 60 * 60 * 24));
  const dokuKomplett = dokuStatus === 'komplett' || dokuStatus === 'vollstaendig';

  // ---- TAG 3: ERSTE DOKUMENTE-ERINNERUNG ----
  if (!dokuKomplett && tageSeit >= 3 && tageSeit < 7) {
    const key = `${telefon}_followup_tag3`;
    if (!gesendet.has(key)) {
      results.push({ json: {
        schuelerName: name, schuelerTelefon: telefon,
        followupSchritt: 'followup_tag3', tageSeit,
        nachricht: `Hallo ${name}! 👋\n\nKurze Erinnerung: Fuer Ihre Fahrschul-Anmeldung fehlen uns noch folgende Unterlagen:\n\n✅ Sehtest\n✅ Erste-Hilfe-Bescheinigung\n✅ Biometrisches Passfoto\n✅ Personalausweis-Kopie\n\nSchicken Sie uns die Dokumente einfach als Foto per WhatsApp oder bringen Sie sie vorbei. Je frueher, desto schneller koennen Sie starten! 🚀\n\nIhre Fahrschule`
      }});
    }
  }

  // ---- TAG 7: ZWEITE ERINNERUNG + THEORIE-TERMIN VORSCHLAG ----
  if (tageSeit >= 7 && tageSeit < 14) {

    // Dokumente-Erinnerung (nur wenn noch nicht komplett)
    if (!dokuKomplett) {
      const key = `${telefon}_followup_tag7`;
      if (!gesendet.has(key)) {
        results.push({ json: {
          schuelerName: name, schuelerTelefon: telefon,
          followupSchritt: 'followup_tag7', tageSeit,
          nachricht: `Hallo ${name},\n\nwir vermissen noch Ihre Unterlagen fuer die Anmeldung. Ohne diese koennen wir Ihren Fuehrerscheinantrag beim TUeV leider nicht stellen.\n\n📋 Noch benoetigt:\n• Sehtest (beim Optiker, meist ohne Termin)\n• Erste-Hilfe-Kurs\n• Passfoto\n• Ausweis-Kopie\n\nBrauchen Sie Hilfe bei der Beschaffung? Wir helfen gerne weiter!\n\nIhre Fahrschule`
        }});
      }
    }

    // Theorie-Termin vorschlagen (unabhaengig von Doku-Status)
    if (theorieStatus !== 'aktiv' && theorieStatus !== 'bestanden') {
      const key = `${telefon}_theorie_termin_vorschlag`;
      if (!gesendet.has(key)) {
        const theorieZeiten = $env.THEORIE_ZEITEN || 'Di + Do, 18:30 Uhr';
        results.push({ json: {
          schuelerName: name, schuelerTelefon: telefon,
          followupSchritt: 'theorie_termin_vorschlag', tageSeit,
          nachricht: `Hallo ${name}! 📚\n\nSie sind jetzt eine Woche angemeldet --- Zeit fuer den naechsten Schritt!\n\nUnsere Theorie-Stunden finden statt:\n🗓 ${theorieZeiten}\n\nMoechten Sie ab naechster Woche starten? Antworten Sie einfach mit:\n✅ JA\n\nOder nutzen Sie unseren kostenlosen Online-Trainer, um sich vorzubereiten:\n📱 ${$env.WEBSITE_URL || ''}/theorie\n\nIhre Fahrschule 🚗`
        }});
      }
    }
  }

  // ---- TAG 14: LETZTE DOKU-WARNUNG ----
  if (!dokuKomplett && tageSeit >= 14 && tageSeit < 28) {
    const key = `${telefon}_followup_tag14`;
    if (!gesendet.has(key)) {
      results.push({ json: {
        schuelerName: name, schuelerTelefon: telefon,
        followupSchritt: 'followup_tag14', tageSeit,
        nachricht: `Hallo ${name},\n\nIhre Anmeldung liegt nun seit 2 Wochen vor, aber die erforderlichen Unterlagen fehlen noch.\n\n⚠️ Ohne Sehtest, Erste-Hilfe und Passfoto koennen wir leider nicht fuer Sie den Fuehrerscheinantrag stellen.\n\nMoechten Sie Ihre Anmeldung aufrechterhalten? Dann reichen Sie die Unterlagen bitte in den naechsten Tagen ein.\n\nBei Fragen: Rufen Sie uns an oder antworten Sie direkt hier.\n\nIhre Fahrschule`
      }});
    }
  }
}

return results.length > 0 ? results : [{ json: { skip: true } }];
